// ============================================
// HELPER FUNCTIONS
// ============================================

export function getProductBySlug(slug: string): ProductItem | undefined {
  return allProducts.find(p => p.slug === slug);
}

export function getProductsByCategory(categorySlug: string): ProductItem[] {
  return allProducts.filter(p => p.therapeuticArea === categorySlug);
}

export function getFeaturedProducts(): ProductItem[] {
  return allProducts.filter(p => p.featured);
}

export function searchProducts(query: string): ProductItem[] {
  const q = query.toLowerCase();
  return allProducts.filter(p =>
    p.name.toLowerCase().includes(q) ||
    p.composition.toLowerCase().includes(q) ||
    p.brand.toLowerCase().includes(q) ||
    p.indications.some(i => i.toLowerCase().includes(q))
  );
}

export function getCategoryBySlug(slug: string): CategoryInfo | undefined {
  return categories.find(c => c.slug === slug);
}

export function getRelatedProducts(product: ProductItem, limit = 4): ProductItem[] {
  return allProducts
    .filter(p => p.therapeuticArea === product.therapeuticArea && p.id !== product.id)
    .slice(0, limit);
}

export function getProductImage(product: ProductItem): string {
  // Use local image if available (for own products)
  if (product.id === "rna-plus") return "/products/rna-plus.jpg";
  if (product.id === "jyspro-df") return "/products/jyspro-df.jpg";
  // For other products, return empty (will use CSS-based card)
  return "";
}
